// CardSwiper.tsx

import React from 'react';
import { Swiper, SwiperSlide } from 'react-id-swiper';
import 'swiper/css/swiper.css'; // Import Swiper styles

import './CardSwiper.css'; // Add your custom styles here

const CardSwiper: React.FC = () => {
  const swiperParams = {
    spaceBetween: 20,
    slidesPerView: 'auto',
    pagination: {
      el: '.swiper-pagination',
      clickable: true,
    },
    navigation: {
      nextEl: '.swiper-button-next',
      prevEl: '.swiper-button-prev',
    },
  };

  return (
    <Swiper {...swiperParams}>
      <SwiperSlide>
        <div className="swiper-card">
          <img src="https://placekitten.com/400/300" alt="Card Image" />
          <p>Card 1 Content</p>
        </div>
      </SwiperSlide>
      <SwiperSlide>
        <div className="swiper-card">
          <img src="https://placekitten.com/400/301" alt="Card Image" />
          <p>Card 2 Content</p>
        </div>
      </SwiperSlide>
      <SwiperSlide>
        <div className="swiper-card">
          <img src="https://placekitten.com/400/302" alt="Card Image" />
          <p>Card 3 Content</p>
        </div>
      </SwiperSlide>
      {/* Add more slides as needed */}
    </Swiper>
  );
};

export default CardSwiper;
